// Arrow Function sintaksisi
const funksiyaAdi = (parametr1, parametr2) => {
  // funksiyanın kodu
  return nəticə;
};

// Və ya daha qısa
const funksiyaAdi = (parametr) => nəticə;

// Arrow Function ilə toplama
const topla = (a, b) => {
  return a + b;
};

// Funksiyanı çağırıram
console.log(topla(2, 3)); // nəticə: 5
console.log(topla(10, 20)); // nəticə: 30

// Qısa Arrow Function
const kvadrat = (x) => x * x;
const ikiqat = (x) => x * 2;
const salam = (ad) => 'Salam, ' + ad + '!';

// Funksiyaları çağırıram
console.log(kvadrat(5)); // nəticə: 25
console.log(ikiqat(7)); // nəticə: 14
console.log(salam('Murad')); // nəticə: Salam, Murad!

// Tək parametr üçün mötərizə lazım deyil
const kvadrat = x => x * x;
const kub = x => x * x * x;
const cütmü = x => x % 2 === 0;

// Funksiyaları çağırıram
console.log(kvadrat(4)); // nəticə: 16
console.log(kub(3)); // nəticə: 27
console.log(cütmü(6)); // nəticə: true

// Parametrsiz Arrow Function
const salamVer = () => 'Salam, dünya!';
const təsadüfiEded = () => Math.floor(Math.random() * 100);

// Funksiyaları çağırıram
console.log(salamVer()); // nəticə: Salam, dünya!
console.log(təsadüfiEded()); // nəticə: 0-99 arası təsadüfi ədəd

// Çoxlu parametr üçün mötərizə lazımdır
const topla = (a, b) => a + b;
const vur = (a, b) => a * b;
const maksimum = (a, b) => a > b ? a : b;

// Funksiyaları çağırıram
console.log(topla(5, 3)); // nəticə: 8
console.log(vur(4, 6)); // nəticə: 24
console.log(maksimum(10, 7)); // nəticə: 10

// Function Declaration
function topla(a, b) {
  return a + b;
}

// Arrow Function
const toplaArrow = (a, b) => a + b;

// Nəticə eynidir
console.log(topla(2, 3)); // nəticə: 5
console.log(toplaArrow(2, 3)); // nəticə: 5

// Function Declaration - öz this-ini yaradır
function normalFunksiya() {
  console.log(this);
}

// Arrow Function - ətraf mühitdən this götürür
const arrowFunksiya = () => {
  console.log(this);
};

// Test edək
normalFunksiya(); // Window obyekti (brauzerdə)
arrowFunksiya(); // Window obyekti (brauzerdə)

